import base64
import zlib
import logging
from lxml import etree
from datetime import datetime, timezone

logger = logging.getLogger(__name__)

SAML2_PROTOCOL_NS = 'urn:oasis:names:tc:SAML:2.0:protocol'
SAML2_ASSERTION_NS = 'urn:oasis:names:tc:SAML:2.0:assertion'
XMLDSIG_NS = 'http://www.w3.org/2000/09/xmldsig#'

SAML_NAMESPACES = {
    'samlp': SAML2_PROTOCOL_NS,
    'saml': SAML2_ASSERTION_NS,
    'ds': XMLDSIG_NS,
}

SAML_RESPONSE_SCHEMA = """<?xml version="1.0" encoding="UTF-8"?>
<xs:schema xmlns:xs="http://www.w3.org/2001/XMLSchema"
           targetNamespace="urn:oasis:names:tc:SAML:2.0:protocol"
           xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
           xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion">
    <xs:import namespace="urn:oasis:names:tc:SAML:2.0:assertion"/>
    <xs:element name="Response">
        <xs:complexType>
            <xs:sequence>
                <xs:any processContents="lax" minOccurs="0" maxOccurs="unbounded"/>
            </xs:sequence>
            <xs:attribute name="ID" type="xs:string" use="required"/>
            <xs:attribute name="Version" type="xs:string" use="required"/>
            <xs:attribute name="IssueInstant" type="xs:string" use="required"/>
            <xs:anyAttribute processContents="lax"/>
        </xs:complexType>
    </xs:element>
</xs:schema>"""


class SAMLValidationError(Exception):
    """Raised when SAML XML validation fails."""
    pass


class SAMLXMLValidator:
    """Validates SAML XML structure and content."""

    def __init__(self):
        self.errors = []

    def decode_saml_response(self, encoded_response):
        """Decode a base64-encoded SAML response."""
        try:
            decoded = base64.b64decode(encoded_response)
            try:
                decoded = zlib.decompress(decoded, -15)
            except zlib.error:
                pass
            return decoded
        except Exception as e:
            raise SAMLValidationError(f"Failed to decode SAML response: {str(e)}")

    def parse_xml(self, xml_bytes):
        """Parse XML bytes into an etree element, with security measures."""
        try:
            parser = etree.XMLParser(
                resolve_entities=False,
                no_network=True,
                remove_comments=True,
                huge_tree=False,
            )
            if isinstance(xml_bytes, str):
                xml_bytes = xml_bytes.encode('utf-8')
            root = etree.fromstring(xml_bytes, parser=parser)
            return root
        except etree.XMLSyntaxError as e:
            raise SAMLValidationError(f"Invalid XML syntax: {str(e)}")

    def validate_structure(self, root):
        """Validate basic SAML Response XML structure."""
        self.errors = []

        # Check root element
        tag = etree.QName(root.tag)
        if tag.localname != 'Response':
            self.errors.append(f"Root element must be 'Response', got '{tag.localname}'")
            raise SAMLValidationError(self.errors)

        if tag.namespace != SAML2_PROTOCOL_NS:
            self.errors.append(
                f"Root element namespace must be '{SAML2_PROTOCOL_NS}', "
                f"got '{tag.namespace}'"
            )

        # Check required attributes
        required_attrs = ['ID', 'Version', 'IssueInstant']
        for attr in required_attrs:
            if root.get(attr) is None:
                self.errors.append(f"Missing required attribute: {attr}")

        # Check Version
        version = root.get('Version')
        if version and version != '2.0':
            self.errors.append(f"Unsupported SAML version: {version}")

        # Check for Status element
        status = root.find('.//samlp:Status', SAML_NAMESPACES)
        if status is None:
            self.errors.append("Missing Status element")
        else:
            status_code = status.find('samlp:StatusCode', SAML_NAMESPACES)
            if status_code is None:
                self.errors.append("Missing StatusCode element")
            else:
                status_value = status_code.get('Value', '')
                if 'Success' not in status_value:
                    status_message_elem = status.find('samlp:StatusMessage', SAML_NAMESPACES)
                    status_message = ''
                    if status_message_elem is not None and status_message_elem.text:
                        status_message = status_message_elem.text
                    self.errors.append(
                        f"SAML authentication failed. Status: {status_value}. "
                        f"Message: {status_message}"
                    )

        # Check for at least one Assertion
        assertions = root.findall('.//saml:Assertion', SAML_NAMESPACES)
        encrypted_assertions = root.findall(
            './/saml:EncryptedAssertion', SAML_NAMESPACES
        )
        if not assertions and not encrypted_assertions:
            self.errors.append("No Assertion or EncryptedAssertion found")

        # Validate each assertion
        for assertion in assertions:
            self._validate_assertion(assertion)

        if self.errors:
            raise SAMLValidationError('; '.join(self.errors))

        return True

    def _validate_assertion(self, assertion):
        """Validate individual assertion structure."""
        # Check Issuer
        issuer = assertion.find('saml:Issuer', SAML_NAMESPACES)
        if issuer is None:
            self.errors.append("Assertion missing Issuer element")

        # Check Subject
        subject = assertion.find('saml:Subject', SAML_NAMESPACES)
        if subject is None:
            self.errors.append("Assertion missing Subject element")
        else:
            name_id = subject.find('saml:NameID', SAML_NAMESPACES)
            if name_id is None:
                self.errors.append("Subject missing NameID element")

        # Check Conditions (optional but validate if present)
        conditions = assertion.find('saml:Conditions', SAML_NAMESPACES)
        if conditions is not None:
            self._validate_conditions(conditions)

        # Check AuthnStatement
        authn_statements = assertion.findall('saml:AuthnStatement', SAML_NAMESPACES)
        if not authn_statements:
            self.errors.append("Assertion missing AuthnStatement")

    def _validate_conditions(self, conditions):
        """Validate assertion conditions including time constraints."""
        now = datetime.now(timezone.utc)

        not_before = conditions.get('NotBefore')
        if not_before:
            try:
                not_before_dt = datetime.fromisoformat(
                    not_before.replace('Z', '+00:00')
                )
                # Allow 5 minutes clock skew
                from datetime import timedelta
                if now < not_before_dt - timedelta(minutes=5):
                    self.errors.append(
                        f"Assertion not yet valid. NotBefore: {not_before}"
                    )
            except ValueError:
                self.errors.append(f"Invalid NotBefore datetime format: {not_before}")

        not_on_or_after = conditions.get('NotOnOrAfter')
        if not_on_or_after:
            try:
                not_on_or_after_dt = datetime.fromisoformat(
                    not_on_or_after.replace('Z', '+00:00')
                )
                from datetime import timedelta
                if now >= not_on_or_after_dt + timedelta(minutes=5):
                    self.errors.append(
                        f"Assertion has expired. NotOnOrAfter: {not_on_or_after}"
                    )
            except ValueError:
                self.errors.append(
                    f"Invalid NotOnOrAfter datetime format: {not_on_or_after}"
                )

    def validate_destination(self, root, expected_acs_url):
        """Validate the Destination attribute matches our ACS URL."""
        destination = root.get('Destination')
        if destination and destination != expected_acs_url:
            raise SAMLValidationError(
                f"Destination mismatch. Expected '{expected_acs_url}', "
                f"got '{destination}'"
            )

    def validate_issuer(self, root, expected_issuer):
        """Validate the Issuer matches the expected IdP entity ID."""
        issuer = root.find('saml:Issuer', SAML_NAMESPACES)
        if issuer is not None and issuer.text != expected_issuer:
            raise SAMLValidationError(
                f"Issuer mismatch. Expected '{expected_issuer}', "
                f"got '{issuer.text}'"
            )


# saml_sp/response_parser.py
import logging
from lxml import etree
from .xml_validator import (
    SAML_NAMESPACES,
    SAMLXMLValidator,
    SAMLValidationError,
)

logger = logging.getLogger(__name__)


class SAMLAttribute:
    """Represents a parsed SAML attribute."""

    def __init__(self, name, friendly_name=None, name_format=None, values=None):
        self.name = name
        self.friendly_name = friendly_name or ''
        self.name_format = name_format or ''
        self.values = values or []

    def __repr__(self):
        return f"SAMLAttribute(name='{self.name}', values={self.values})"

    @property
    def value(self):
        """Return the first value or None."""
        return self.values[0] if self.values else None


class SAMLResponseData:
    """Container for parsed SAML response data."""

    def __init__(self):
        self.name_id = None
        self.name_id_format = None
        self.session_index = None
        self.issuer = None
        self.attributes = {}
        self.raw_attributes = {}
        self.authn_instant = None
        self.authn_context = None
        self.response_id = None
        self.assertion_id = None

    def get_attribute(self, name, default=None):
        """Get attribute value by name or mapped name."""
        attr = self.attributes.get(name)
        if attr:
            return attr.value
        # Try raw attributes
        return self.raw_attributes.get(name, [default])[0] if name in self.raw_attributes else default

    def get_attribute_values(self, name):
        """Get all values for an attribute."""
        attr = self.attributes.get(name)
        if attr:
            return attr.values
        return self.raw_attributes.get(name, [])

    def get_mapped_attributes(self, attribute_mapping):
        """Map SAML attributes to friendly names using the provided mapping."""
        mapped = {}
        for saml_name, friendly_name in attribute_mapping.items():
            if saml_name in self.attributes:
                mapped[friendly_name] = self.attributes[saml_name].value
            elif saml_name in self.raw_attributes:
                values = self.raw_attributes[saml_name]
                mapped[friendly_name] = values[0] if values else None
        return mapped


class SAMLResponseParser:
    """Parses SAML POST responses and extracts user information."""

    def __init__(self, saml_settings=None):
        from django.conf import settings
        self.saml_settings = saml_settings or getattr(settings, 'SAML_SP_SETTINGS', {})
        self.validator = SAMLXMLValidator()

    def parse(self, encoded_response):
        """
        Parse an encoded SAML response.
        Returns SAMLResponseData with extracted information.
        """
        # Decode
        xml_bytes = self.validator.decode_saml_response(encoded_response)
        logger.debug("Decoded SAML response XML")

        # Parse XML
        root = self.validator.parse_xml(xml_bytes)
        logger.debug("Parsed SAML response XML")

        # Validate structure
        self.validator.validate_structure(root)
        logger.debug("SAML response structure validated")

        # Validate destination
        acs_url = self.saml_settings.get('acs_url', '')
        if acs_url:
            self.validator.validate_destination(root, acs_url)

        # Validate issuer
        idp_entity_id = self.saml_settings.get('idp_entity_id', '')
        if idp_entity_id:
            self.validator.validate_issuer(root, idp_entity_id)

        # Extract data
        response_data = self._extract_response_data(root)
        logger.info(
            f"SAML response parsed successfully. NameID: {response_data.name_id}"
        )

        return response_data

    def _extract_response_data(self, root):
        """Extract all relevant data from the SAML response."""
        data = SAMLResponseData()

        # Response-level data
        data.response_id = root.get('ID')

        # Response-level issuer
        issuer = root.find('saml:Issuer', SAML_NAMESPACES)
        if issuer is not None:
            data.issuer = issuer.text

        # Find assertion
        assertion = root.find('.//saml:Assertion', SAML_NAMESPACES)
        if assertion is None:
            raise SAMLValidationError("No Assertion found in response")

        data.assertion_id = assertion.get('ID')

        # Extract NameID
        self._extract_name_id(assertion, data)

        # Extract session index
        self._extract_session_index(assertion, data)

        # Extract authentication context
        self._extract_authn_context(assertion, data)

        # Extract attributes
        self._extract_attributes(assertion, data)

        return data

    def _extract_name_id(self, assertion, data):
        """Extract NameID from the assertion Subject."""
        subject = assertion.find('saml:Subject', SAML_NAMESPACES)
        if subject is not None:
            name_id_elem = subject.find('saml:NameID', SAML_NAMESPACES)
            if name_id_elem is not None:
                data.name_id = name_id_elem.text
                data.name_id_format = name_id_elem.get('Format', '')
            else:
                raise SAMLValidationError("NameID not found in Subject")
        else:
            raise SAMLValidationError("Subject not found in Assertion")

    def _extract_session_index(self, assertion, data):
        """Extract SessionIndex from AuthnStatement."""
        authn_statement = assertion.find('saml:AuthnStatement', SAML_NAMESPACES)
        if authn_statement is not None:
            data.session_index = authn_statement.get('SessionIndex', '')
            data.authn_instant = authn_statement.get('AuthnInstant', '')

    def _extract_authn_context(self, assertion, data):
        """Extract authentication context class reference."""
        authn_context = assertion.find(
            './/saml:AuthnStatement/saml:AuthnContext/saml:AuthnContextClassRef',
            SAML_NAMESPACES
        )
        if authn_context is not None:
            data.authn_context = authn_context.text

    def _extract_attributes(self, assertion, data):
        """Extract all attributes from the assertion's AttributeStatement."""
        attr_statement = assertion.find(
            'saml:AttributeStatement', SAML_NAMESPACES
        )
        if attr_statement is None:
            logger.warning("No AttributeStatement found in assertion")
            return

        for attr_elem in attr_statement.findall('saml:Attribute', SAML_NAMESPACES):
            name = attr_elem.get('Name', '')
            friendly_name = attr_elem.get('FriendlyName', '')
            name_format = attr_elem.get('NameFormat', '')

            values = []
            for value_elem in attr_elem.findall(
                'saml:AttributeValue', SAML_NAMESPACES
            ):
                if value_elem.text:
                    values.append(value_elem.text.strip())
                else:
                    # Handle nested XML in attribute values
                    inner_xml = etree.tostring(
                        value_elem, encoding='unicode', method='text'
                    )
                    if inner_xml and inner_xml.strip():
                        values.append(inner_xml.strip())

            saml_attr = SAMLAttribute(
                name=name,
                friendly_name=friendly_name,
                name_format=name_format,
                values=values
            )

            data.attributes[name] = saml_attr
            data.raw_attributes[name] = values

            # Also index by friendly name if available
            if friendly_name:
                data.attributes[friendly_name] = saml_attr
                data.raw_attributes[friendly_name] = values

        logger.debug(
            f"Extracted {len(data.attributes)} attributes from assertion"
        )


# saml_sp/backends.py
import logging
from django.conf import settings
from django.contrib.auth import get_user_model
from django.contrib.auth.backends import BaseBackend

logger = logging.getLogger(__name__)
User = get_user_model()


class SAMLBackend(BaseBackend):
    """Django authentication backend for SAML."""

    def authenticate(self, request, saml_response_data=None, **kwargs):
        """Authenticate user based on SAML response data."""
        if saml_response_data is None:
            return None

        saml_settings = getattr(settings, 'SAML_SP_SETTINGS', {})
        attribute_mapping = saml_settings.get('attribute_mapping', {})
        create_unknown = saml_settings.get('create_unknown_user', True)
        update_on_login = saml_settings.get('update_user_on_login', True)

        # Map attributes
        mapped_attrs = saml_response_data.get_mapped_attributes(attribute_mapping)
        logger.debug(f"Mapped attributes: {mapped_attrs}")

        # Determine username
        username = self._get_username(saml_response_data, mapped_attrs)
        if not username:
            logger.error("Could not determine username from SAML response")
            return None

        # Get or create user
        user = self._get_or_create_user(
            username, mapped_attrs, create_unknown, update_on_login
        )

        return user

    def _get_username(self, saml_response_data, mapped_attrs):
        """Determine username from SAML data."""
        # Try mapped username attribute first
        username = mapped_attrs.get('username')
        if username:
            return username

        # Try email as username
        email = mapped_attrs.get('email')
        if email:
            return email

        # Fall back to NameID
        return saml_response_data.name_id

    def _get_or_create_user(self, username, mapped_attrs, create_unknown, update_on_login):
        """Get existing user or create a new one."""
        try:
            user = User.objects.get(username=username)
            if update_on_login:
                self._update_user(user, mapped_attrs)
            logger.info(f"Authenticated existing user: {username}")
            return user
        except User.DoesNotExist:
            if create_unknown:
                user = self._create_user(username, mapped_attrs)
                logger.info(f"Created new user from SAML: {username}")
                return user
            else:
                logger.warning(
                    f"User '{username}' not found and creation disabled"
                )
                return None

    def _create_user(self, username, mapped_attrs):
        """Create a new Django user from SAML attributes."""
        user = User(username=username)
        user.set_unusable_password()  # SAML users don't need local passwords

        self._apply_attributes(user, mapped_attrs)
        user.save()

        return user

    def _update_user(self, user, mapped_attrs):
        """Update existing user with SAML attributes."""
        changed = self._apply_attributes(user, mapped_attrs)
        if changed:
            user.save()
            logger.debug(f"Updated user {user.username} with SAML attributes")

    def _apply_attributes(self, user, mapped_attrs):
        """Apply mapped attributes to user object. Returns True if any changed."""
        changed = False
        field_names = {f.name for f in User._meta.get_fields()}

        for attr_name, attr_value in mapped_attrs.items():
            if attr_value and attr_name in field_names and attr_name != 'username':
                current_value = getattr(user, attr_name, None)
                if current_value != attr_value:
                    setattr(user, attr_name, attr_value)
                    changed = True

        return changed

    def get_user(self, user_id):
        """Retrieve user by ID."""
        try:
            return User.objects.get(pk=user_id)
        except User.DoesNotExist:
            return None


# saml_sp/session_manager.py
import logging
from datetime import timedelta
from django.utils import timezone
from django.contrib.auth import login as django_login
from .models import SAMLSession

logger = logging.getLogger(__name__)


class SAMLSessionManager:
    """Manages Django user sessions based on SAML authentication."""

    def __init__(self, request):
        self.request = request

    def create_session(self, user, saml_response_data, session_duration_hours=8):
        """
        Create a Django session and SAML session record for the authenticated user.
        """
        # Log in the user to create a Django session
        django_login(
            self.request,
            user,
            backend='saml_sp.backends.SAMLBackend'
        )

        # Calculate session expiry
        expires_at = timezone.now() + timedelta(hours=session_duration_hours)

        # Deactivate any existing SAML sessions for this user
        SAMLSession.objects.filter(
            user=user,
            is_active=True
        ).update(is_active=False)

        # Create SAML session record
        saml_session = SAMLSession.objects.create(
            user=user,
            name_id=saml_response_data.name_id,
            name_id_format=saml_response_data.name_id_format or '',
            session_index=saml_response_data.session_index or '',
            attributes=saml_response_data.raw_attributes,
            expires_at=expires_at,
            is_active=True,
        )

        # Store SAML session info in Django session
        self.request.session['saml_session_id'] = saml_session.id
        self.request.session['saml_name_id'] = saml_response_data.name_id
        self.request.session['saml_session_index'] = (
            saml_response_data.session_index or ''
        )

        logger.info(
            f"Created SAML session {saml_session.id} for user {user.username}"
        )

        return saml_session

    def terminate_session(self):
        """Terminate the current SAML session."""
        saml_session_id = self.request.session.get('saml_session_id')
        if saml_session_id:
            SAMLSession.objects.filter(id=saml_session_id).update(
                is_active=False
            )
            logger.info(f"Terminated SAML session {saml_session_id}")

        # Clean up Django session
        for key in ['saml_session_id', 'saml_name_id', 'saml_session_index']:
            self.request.session.pop(key, None)

    def get_active_session(self):
        """Get the current active SAML session."""
        saml_session_id = self.request.session.get('saml_session_id')
        if not saml_session_id:
            return None

        try:
            session = SAMLSession.objects.get(
                id=saml_session_id,
                is_active=True,
            )

            # Check expiry
            if session.expires_at and session.expires_at < timezone.now():
                session.is_active = False
                session.save()
                logger.info(f"SAML session {session.id} has expired")
                return None

            return session
        except SAMLSession.DoesNotExist:
            return None

    @staticmethod
    def cleanup_expired_sessions():
        """Clean up expired SAML sessions."""
        expired_count = SAMLSession.objects.filter(
            is_active=True,
            expires_at__lt=timezone.now()
        ).update(is_active=False)

        if expired_count:
            logger.info(f"Cleaned up {expired_count} expired SAML sessions")

        return expired_count


