from .session_manager import SAMLSessionManager
from .xml_validator import SAMLValidationError

logger = logging.getLogger(__name__)


@method_decorator(csrf_exempt, name='dispatch')
class SAMLACSView(View):
    """
    Assertion Consumer Service (ACS) endpoint.
    Handles SAML POST responses from the Identity Provider.
    """

    def post(self, request):
        """Process SAML Response via HTTP-POST binding."""
        saml_response_encoded = request.POST.get('SAMLResponse')
        relay_state = request.POST.get('RelayState', '/')

        if not saml_response_encoded:
            logger.error("No SAMLResponse found in POST data")
            return HttpResponseBadRequest("Missing SAMLResponse parameter")

        try:
            # Parse and validate the SAML response
            parser = SAMLResponseParser()
            response_data = parser.parse(saml_response_encoded)

            # Authenticate the user
            user = authenticate(
                request,
                saml_response_data=response_data,
            )

            if user is None:
                logger.error("SAML authentication failed - no user returned")
                return HttpResponseBadRequest(
                    "Authentication failed. Unable to authenticate user."
                )

            if not user.is_active:
                logger.error(f"SAML user {user.username} is inactive")
                return HttpResponseBadRequest(
                    "Authentication failed. User account is disabled."
                )

            # Create session
            session_manager = SAMLSessionManager(request)
            session_manager.create_session(user, response_data)

            logger.info(
                f"SAML SSO successful for user {user.username} "
                f"(NameID: {response_data.name_id})"
            )

            # Redirect to RelayState or default
            redirect_url = self._validate_relay_state(relay_state)
            return HttpResponseRedirect(redirect_url)

        except SAMLValidationError as e:
            logger.error(f"SAML validation error: {str(e)}")
            return HttpResponseBadRequest(f"SAML Validation Error: {str(e)}")
        except Exception as e:
            logger.exception(f"Unexpected error processing SAML response: {str(e)}")
            return HttpResponseBadRequest(
                "An error occurred processing the SAML response."
            )

    def _validate_relay_state(self, relay_state):
        """Validate and sanitize the RelayState URL."""
        if not relay_state:
            return '/'

        # Only allow relative URLs or URLs to our domain
        parsed = urllib.parse.urlparse(relay_state)
        if parsed.scheme and parsed.netloc:
            allowed_hosts = getattr(settings, 'ALLOWED_HOSTS', [])
            if parsed.netloc not in allowed_hosts:
                logger.warning(
                    f"Invalid RelayState domain: {parsed.netloc}"
                )
                return '/'

        return relay_state


class SAMLLoginView(View):
    """Initiates SAML SSO by redirecting to the IdP."""

    def get(self, request):
        """Generate SAML AuthnRequest and redirect to IdP."""
        saml_settings = getattr(settings, 'SAML_SP_SETTINGS', {})

        idp_sso_url = saml_settings.get('idp_sso_url', '')
        entity_id = saml_settings.get('entity_id', '')
        acs_url = saml_settings.get('acs_url', '')
        relay_state = request.GET.get('next', '/')

        if not idp_sso_url:
            return HttpResponseBadRequest("IdP SSO URL not configured")

        # Generate AuthnRequest
        import uuid
        from datetime import datetime, timezone
        request_id = f"_{''.join(str(uuid.uuid4()).split('-'))}"
        issue_instant = datetime.now(timezone.utc).strftime(
            '%Y-%m-%dT%H:%M:%SZ'
        )

        authn_request = f"""<samlp:AuthnRequest
    xmlns:samlp="urn:oasis:names:tc:SAML:2.0:protocol"
    xmlns:saml="urn:oasis:names:tc:SAML:2.0:assertion"
    ID="{request_id}"
    Version="2.0"
    IssueInstant="{issue_instant}"
    Destination="{idp_sso_url}"
    AssertionConsumerServiceURL="{acs_url}"
    ProtocolBinding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST">
    <saml:Issuer>{entity_id}</saml:Issuer>
    <samlp:NameIDPolicy
        Format="urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress"
        AllowCreate="true"/>
</samlp:AuthnRequest>"""

        encoded_request = base64.b64encode(
            authn_request.encode('utf-8')
        ).decode('utf-8')

        # Build redirect URL with POST binding form
        context = {
            'idp_sso_url': idp_sso_url,
            'saml_request': encoded_request,
            'relay_state': relay_state,
        }

        # Return auto-submitting form for POST binding
        html = f"""<!DOCTYPE html>
<html>
<head><title>Redirecting to Identity Provider...</title></head>
<body onload="document.forms[0].submit();">
    <noscript><p>JavaScript is required. Please click the button below.</p></noscript>
    <form method="POST" action="{idp_sso_url}">
        <input type="hidden" name="SAMLRequest" value="{encoded_request}"/>
        <input type="hidden" name="RelayState" value="{relay_state}"/>
        <noscript><input type="submit" value="Continue"/></noscript>
    </form>
</body>
</html>"""
        return HttpResponse(html)


class SAMLLogoutView(View):
    """Handles SAML logout."""

    def get(self, request):
        """Initiate logout."""
        session_manager = SAMLSessionManager(request)
        session_manager.terminate_session()
        django_logout(request)

        saml_settings = getattr(settings, 'SAML_SP_SETTINGS', {})
        idp_slo_url = saml_settings.get('idp_slo_url', '')

        if idp_slo_url:
            # Redirect to IdP for single logout
            return HttpResponseRedirect(idp_slo_url)

        return HttpResponseRedirect('/')

    def post(self, request):
        """Handle SLO response from IdP."""
        session_manager = SAMLSessionManager(request)
        session_manager.terminate_session()
        django_logout(request)
        return HttpResponseRedirect('/')


class SAMLMetadataView(View):
    """Serves SP metadata XML."""

    def get(self, request):
        """Generate and return SP metadata."""
        saml_settings = getattr(settings, 'SAML_SP_SETTINGS', {})

        entity_id = saml_settings.get('entity_id', '')
        acs_url = saml_settings.get('acs_url', '')
        sls_url = saml_settings.get('sls_url', '')

        metadata = f"""<?xml version="1.0" encoding="UTF-8"?>
<md:EntityDescriptor
    xmlns:md="urn:oasis:names:tc:SAML:2.0:metadata"
    entityID="{entity_id}">
    <md:SPSSODescriptor
        AuthnRequestsSigned="false"
        WantAssertionsSigned="true"
        protocolSupportEnumeration="urn:oasis:names:tc:SAML:2.0:protocol">
        <md:SingleLogoutService
            Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"
            Location="{sls_url}"/>
        <md:NameIDFormat>urn:oasis:names:tc:SAML:1.1:nameid-format:emailAddress</md:NameIDFormat>
        <md:NameIDFormat>urn:oasis:names:tc:SAML:2.0:nameid-format:persistent</md:NameIDFormat>
        <md:NameIDFormat>urn:oasis:names:tc:SAML:2.0:nameid-format:transient</md:NameIDFormat>
        <md:AssertionConsumerService
            Binding="urn:oasis:names:tc:SAML:2.0:bindings:HTTP-POST"
            Location="{acs_url}"
            index="1"
            isDefault="true"/>
    </md:SPSSODescriptor>
</md:EntityDescriptor>"""

        return HttpResponse(metadata, content_type='application/xml')


# saml_sp/middleware.py
import logging
from django.utils.deprecation import MiddlewareMixin
from .session_manager import SAMLSessionManager

logger = logging.getLogger(__name__)


class SAMLSessionMiddleware(MiddlewareMixin):
    """Middleware to validate SAML sessions on each request."""

    def process_request(self, request):
        """Check if the SAML session is still valid."""
        if not request.user.is_authenticated:
            return None

        saml_session_id = request.session.get('saml_session_id')
        if not saml_session_id:
            return None

        session_manager = SAMLSessionManager(request)
        active_session = session_manager.get_active_session()

        if active_session is None:
            logger.info(
                f"SAML session expired for user {request.user.username}"
            )
            from django.contrib.auth import logout
            logout(request)

        return None


